const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_PREMIUM = 60;

const sumItemBasePremiums = (items: Item[]): number => {
  const components = items.filter((i) => COMPONENT_TYPES.has(i.type));
  const nonComponents = items.filter((i) => !COMPONENT_TYPES.has(i.type));
  const nonComponentSum = nonComponents.reduce((sum, item) => sum + itemBasePremium(item), 0);
  let componentSum = 0;
  if (components.length === 3) {
    componentSum = BLOCK_PREMIUM;
  } else {
    componentSum = components.reduce((sum, item) => sum + itemBasePremium(item), 0);
  }
  return nonComponentSum + componentSum;
};

