export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemBasePremium(item), 0);

const componentsPremium = (components: Item[]): number =>
  components.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBasePremiums(components);

const sumItemBasePremiums = (items: Item[]): number =>
  componentsPremium(items.filter(isComponent)) +
  sumBasePremiums(items.filter((item) => !isComponent(item)));

const quotePremium = (items: Item[]): number =>
  sumItemBasePremiums(items) + PROCESSING_FEE;

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step): StepResult => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

