import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge cases / simplest
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // Base premiums for main items (each + 5 G fee)
  it("single sword → premium 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("single amulet → premium 65 G (60 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it("single staff → premium 85 G (80 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 85 });
  });
  it("single potion → premium 45 G (40 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 45 });
  });

  // Component pricing
  it("2 runes → 50 G base premium (55 G with fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 55 });
  });
  it("3 runes → 60 G base premium block (65 G with fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 65 });
  });
  it("4 runes → 100 G base premium no block (105 G with fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("7 runes → 175 G base premium (180 G with fee; no block since block requires exactly 3)", () => {
    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    expect(result.results[0]).toEqual({ premium: 180 });
  });

  // "Alike" components clarification
  it("2 runes + 1 moonstone → 75 G base premium (80 G with fee; no block: different types)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 80 });
  });
  it("3 runes + 3 moonstones → 120 G base premium (125 G with fee; two separate blocks)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
      ] }],
    });
    expect(result.results[0]).toEqual({ premium: 125 });
  });

  // Item-specific modifiers
  it("cursed sword adds 50% risk surcharge → 100 + 50 = 150 base, 155 with fee", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(result.results[0]).toEqual({ premium: 155 });
  });
  it("highly enchanted sword (enchantment 5) adds 30% surcharge → 130 base, 135 with fee", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 135 });
  });
  it("sword with enchantment 4 → no high-enchantment surcharge (100 base, 105 with fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 105 });
  });
  it("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 = 180, 185 with fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 185 });
  });

  // Policy-wide modifiers
  it("first insurance adds 10% per item → sword 100 + 10 = 110, 115 with fee (per spec ❓: each item in a quote is a first insurance)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it.todo("loyalty discount: customer with exactly 2 years → 20% off policy");
  it.todo("follow-up contract: second quote in scenario gets 15% discount");

  // Modifier scope on multi-item policies
  it.todo("policy with cursed sword + plain amulet → cursed surcharge only on sword's base premium (160 + 50 = 210 before fee and other modifiers)");

  // Rounding
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3 years → 160 G");

  // Claim: standard reimbursement
  it.todo("regular sword damage 500 G → payout 400 G (deductible 100)");
  it.todo("rune damage 200 G → payout 100 G (no special clauses, deductible)");

  // Enchantment threshold vs dragon material
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% rule + deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement minus deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // Multiple items of same type
  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
  it.todo("two sword damages with two swords insured → each treated as separate damage with own deductible");
  it.todo("damages contain more entries of a type than insured (2 sword damages, 1 sword) → claim rejected (error)");

  // Cap exhaustion
  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
  it.todo("cursed sword (premium with modifiers 165) → cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
  it.todo("sword cap 2000, two claims of 1500 each → first payout 1400 (cap 600 remaining), second payout 600 (cap 0)");

  // Payout rounding
  it.todo("payout yielding 350.5 G → final payout 350 G (rounded down)");

  // Edge cases / errors
  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
  it.todo("claim references item not in policy → CLI exits non-zero, error to stderr");
  it.todo("claim contains damage with negative amount → CLI exits non-zero, error to stderr");
});

