import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Edge cases / simplest
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // Per spec ❓: each item in a quote is treated as a first insurance,
  // so a 10% first-insurance surcharge applies on the policy base premium
  // for every quote.

  // Base premiums for main items (base + 10% first-ins + 5 G fee)
  it("single sword → premium 115 G (100 base + 10 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("single amulet → premium 71 G (60 base + 6 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("single staff → premium 93 G (80 base + 8 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("single potion → premium 49 G (40 base + 4 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });

  // Component pricing
  it("2 runes → 50 G base + 5 first-ins + 5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes → 60 G base premium block + 6 first-ins + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes → 100 G base no block + 10 first-ins + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("7 runes → 175 G base + 17.5 first-ins + 5 fee = 197.5 → rounded up to 198 G", () => {
    const items = Array.from({ length: 7 }, () => ({ type: "rune" }));
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items }],
    });
    expect(result.results[0]).toEqual({ premium: 198 });
  });

  // "Alike" components clarification
  it("2 runes + 1 moonstone → 75 G base + 7.5 first-ins + 5 fee = 87.5 → 88 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones → 120 G base (two blocks) + 12 first-ins + 5 fee = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
      ] }],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // Item-specific modifiers (cursed/enchantment apply per item; first-ins still applies on policy base)
  it("cursed sword adds 50% on item base → 100 + 50 curse + 10 first-ins + 5 fee = 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true }] }],
    });
    expect(result.results[0]).toEqual({ premium: 165 });
  });
  it("highly enchanted sword (ench 5) → 100 + 30 ench + 10 first-ins + 5 fee = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 145 });
  });
  it("sword with enchantment 4 → no high-ench surcharge: 100 + 10 first-ins + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("cursed sword with enchantment 5 → 100 + 50 + 30 + 10 first-ins + 5 fee = 195 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 195 });
  });

  // Policy-wide modifiers
  it("first insurance adds 10% per item → sword 100 + 10 = 110, 115 with fee (per spec ❓: each item in a quote is a first insurance)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it.todo("loyalty discount: customer with exactly 2 years → 20% off policy");
  it.todo("follow-up contract: second quote in scenario gets 15% discount");

  // Modifier scope on multi-item policies
  it.todo("policy with cursed sword + plain amulet → cursed surcharge only on sword's base premium (160 + 50 = 210 before fee and other modifiers)");

  // Rounding
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3 years → 160 G");

  // Claim: standard reimbursement
  it.todo("regular sword damage 500 G → payout 400 G (deductible 100)");
  it.todo("rune damage 200 G → payout 100 G (no special clauses, deductible)");

  // Enchantment threshold vs dragon material
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% rule + deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full reimbursement minus deductible)");
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // Multiple items of same type
  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
  it.todo("two sword damages with two swords insured → each treated as separate damage with own deductible");
  it.todo("damages contain more entries of a type than insured (2 sword damages, 1 sword) → claim rejected (error)");

  // Cap exhaustion
  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
  it.todo("cursed sword (premium with modifiers 165) → cap 2000 (based on unmodified insurance value)");
  it.todo("sword + 3 runes block → insurance sum 1750 (block discount affects premium only)");
  it.todo("sword cap 2000, two claims of 1500 each → first payout 1400 (cap 600 remaining), second payout 600 (cap 0)");

  // Payout rounding
  it.todo("payout yielding 350.5 G → final payout 350 G (rounded down)");

  // Edge cases / errors
  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
  it.todo("claim references item not in policy → CLI exits non-zero, error to stderr");
  it.todo("claim contains damage with negative amount → CLI exits non-zero, error to stderr");
});

export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const surchargeRate = (item: Item): number =>
  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);

const itemBasePremium = (item: Item): number => {
  const base = BASE_PREMIUM[item.type] ?? 0;
  return base + base * surchargeRate(item);
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemBasePremium(item), 0);

const groupByType = (items: Item[]): Item[][] => {
  const byType = new Map<string, Item[]>();
  for (const item of items) {
    const group = byType.get(item.type) ?? [];
    group.push(item);
    byType.set(item.type, group);
  }
  return [...byType.values()];
};

const groupPremium = (group: Item[]): number =>
  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBasePremiums(group);

const componentsPremium = (components: Item[]): number =>
  groupByType(components).reduce((total, group) => total + groupPremium(group), 0);

const itemsBasePremium = (items: Item[]): number =>
  componentsPremium(items.filter(isComponent)) +
  sumBasePremiums(items.filter((item) => !isComponent(item)));

const quotePremium = (items: Item[]): number =>
  itemsBasePremium(items) + PROCESSING_FEE;

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step): StepResult => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

