export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface Damage {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: Damage[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const FIRST_INSURANCE_RATE = 0.1;

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const surchargeRate = (item: Item): number =>
  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);

const itemBaseValue = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;

const itemSurcharge = (item: Item): number =>
  itemBaseValue(item) * surchargeRate(item);

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const sumBy = <T>(values: T[], measure: (value: T) => number): number =>
  values.reduce((sum, value) => sum + measure(value), 0);

const groupByType = (items: Item[]): Item[][] => {
  const byType = new Map<string, Item[]>();
  for (const item of items) {
    const group = byType.get(item.type) ?? [];
    group.push(item);
    byType.set(item.type, group);
  }
  return [...byType.values()];
};

const groupPremium = (group: Item[]): number =>
  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBy(group, itemBaseValue);

const componentsPremium = (components: Item[]): number =>
  sumBy(groupByType(components), groupPremium);

const policyBasePremium = (items: Item[]): number =>
  componentsPremium(items.filter(isComponent)) +
  sumBy(items.filter((item) => !isComponent(item)), itemBaseValue);

const totalSurcharges = (items: Item[]): number => sumBy(items, itemSurcharge);

const quotePremium = (items: Item[]): number => {
  const base = policyBasePremium(items);
  const surcharges = totalSurcharges(items);
  const firstInsurance = base * FIRST_INSURANCE_RATE;
  return Math.ceil(base + surcharges + firstInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step): StepResult => {
    if (step.op === "quote") {
      return { premium: quotePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

