interface Policy {
  items: Item[];
  insuranceSum: number;
  remainingCap: number;
}

const insuranceSum = (items: Item[]): number =>
  sumBy(items, (item) => INSURANCE_VALUE[item.type] ?? 0);

const newPolicy = (items: Item[]): Policy => {
  const sum = insuranceSum(items);
  return { items, insuranceSum: sum, remainingCap: sum * CAP_MULTIPLIER };
};

const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
  const damage = incident.damages[0];
  const reimbursable = damage.amount - DEDUCTIBLE;
  const payout = Math.min(reimbursable, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  let quoteCount = 0;
  const policies: Record<number, Policy> = {};
  const results = scenario.steps.map((step, index): StepResult => {
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      quoteCount += 1;
      policies[index] = newPolicy(step.items);
      return { premium: quotePremium(scenario.customer, step.items, isFollowUp) };
    }
    return processClaim(policies[step.policy], step.incident);
  });
  return { results };
};

